def point_type(name, fields, srid_map):
    """
    动态创建一个 Point 子类。

    :param name: 类的名称
    :param fields: 类的字段，通常是一个字典，键为字段名，值为字段类型
    :param srid_map: SRID 映射，通常是一个字典，键为字段名，值为 SRID
    :return: 动态创建的 Point 子类
    """
    class Point:
        def __init__(self, **kwargs):
            for field, value in kwargs.items():
                setattr(self, field, value)

        def __repr__(self):
            fields_str = ', '.join(f"{field}={getattr(self, field)}" for field in self.__dict__)
            return f"{name}({fields_str})"

        def to_wkt(self):
            coords = []
            for field in fields:
                if field in srid_map:
                    coords.append(f"{getattr(self, field)} {srid_map[field]}")
                else:
                    coords.append(str(getattr(self, field)))
            return f"POINT({', '.join(coords)})"

    Point.__name__ = name
    return Point

import warnings

def deprecated(message):
    """
    返回一个用于标记函数和方法为已弃用的装饰器函数。
    用于标记函数和方法为已弃用的装饰器。
    @deprecated("'foo' has been deprecated in favour of 'bar'")
    def foo(x):
        pass
    """
    def decorator(func):
        def wrapper(*args, **kwargs):
            warnings.warn(f"{func.__name__} is deprecated: {message}", DeprecationWarning, stacklevel=2)
            return func(*args, **kwargs)
        return wrapper
    return decorator

