def difference(d1, d2, level=-1):
    """
    返回一个字典，其中包含 *d1* 中不在 *d2* 中的项。

    参数 *level* 用于设置递归的最大深度。对于无限递归，则将其设置为-1。如果设置为 1，当某个键同时存在于 *d1* 和 *d2* 中但其值不同，则该键值对会包含在差异结果中。
    有关更多详细信息，请参阅 :func:`intersection`。

    *d1* 和 *d2* 本身不会被修改。然而，*d1* 或其某些子字典可能会直接作为返回值。如果需要，请对结果进行深拷贝。

    .. 版本新增:: 0.5  
      添加了关键字参数 *level*。
    """
    def _diff(d1, d2, current_level):
        if current_level == 0:
            return {}

        diff_dict = {}
        for key in d1:
            if key not in d2:
                diff_dict[key] = d1[key]
            else:
                if isinstance(d1[key], dict) and isinstance(d2[key], dict):
                    nested_diff = _diff(d1[key], d2[key], current_level - 1 if current_level != -1 else -1)
                    if nested_diff:
                        diff_dict[key] = nested_diff
                elif d1[key] != d2[key]:
                    diff_dict[key] = d1[key]
        return diff_dict

    return _diff(d1, d2, level)

import re

class ValidationError(Exception):
    def __init__(self, messages):
        self.messages = messages
        super().__init__(f"Validation failed with errors: {messages}")

def validate_key(key):
    # Example regex for key validation
    key_regex = r'^[a-zA-Z_][a-zA-Z0-9_]*$'
    if not isinstance(key, str):
        return False, 'expected string or bytes-like object'
    if not re.match(key_regex, key):
        return False, f"Label key '{key}' does not match the regex {key_regex}"
    return True, None

def validate_value(value):
    # Example regex for value validation
    value_regex = r'^[a-zA-Z0-9_]*$'
    if not isinstance(value, str):
        return False, 'expected string or bytes-like object'
    if not re.match(value_regex, value):
        return False, f"Label value '{value}' does not match the regex {value_regex}"
    return True, None

def _validate_labels(labels):
    errors = []
    for key, value in labels.items():
        key_valid, key_error = validate_key(key)
        if not key_valid:
            errors.append({str(key): key_error})

        value_valid, value_error = validate_value(value)
        if not value_valid:
            errors.append({str(value): value_error})

    if errors:
        raise ValidationError(errors)

def generate_default_observer_schema_dict(manifest_dict, first_level=False):
    """
    根据 `manifest_dict` 文件中的值类型（例如字典和列表），生成新字典中不同键对应的值。然后返回新的字典。

    与函数 :func:``generate_default_observer_schema_list`` 一起，该函数被递归调用，用于从部分 Kubernetes 资源中生成默认的 `observer_schema` 的一部分，这些资源分别由 `manifest_dict` 或 `manifest_list` 定义。

    参数:
      manifest_dict (dict): 部分 Kubernetes 资源。
      first_level (bool, 可选): 如果为真，表示该字典代表 Kubernetes 资源的完整 `observer_schema`。

    返回值:
      dict: 生成的部分 `observer_schema`。

    该函数从 `manifest_dict` 创建一个新字典，并将所有非列表和非字典的值替换为 `None`。

    如果是 `first_level` 字典（比如资源的完整 `observer_schema`），则标识字段的值会从 manifest 文件中复制。
    """
    schema_dict = {}
    for key, value in manifest_dict.items():
        if isinstance(value, dict):
            schema_dict[key] = generate_default_observer_schema_dict(value)
        elif isinstance(value, list):
            schema_dict[key] = generate_default_observer_schema_list(value)
        else:
            if first_level and key in ['apiVersion', 'kind', 'metadata']:
                schema_dict[key] = value
            else:
                schema_dict[key] = None
    return schema_dict

def generate_default_observer_schema_list(manifest_list):
    """
    根据 `manifest_list` 文件中的值类型（例如字典和列表），生成新列表中不同元素对应的值。然后返回新的列表。

    与函数 :func:``generate_default_observer_schema_dict`` 一起，该函数被递归调用，用于从部分 Kubernetes 资源中生成默认的 `observer_schema` 的一部分，这些资源分别由 `manifest_dict` 或 `manifest_list` 定义。

    参数:
      manifest_list (list): 部分 Kubernetes 资源。

    返回值:
      list: 生成的部分 `observer_schema`。

    该函数从 `manifest_list` 创建一个新列表，并将所有非列表和非字典的值替换为 `None`。
    """
    schema_list = []
    for item in manifest_list:
        if isinstance(item, dict):
            schema_list.append(generate_default_observer_schema_dict(item))
        elif isinstance(item, list):
            schema_list.append(generate_default_observer_schema_list(item))
        else:
            schema_list.append(None)
    return schema_list

def update_last_applied_manifest_list_from_resp(last_applied_manifest, observer_schema, response):
    """
    与函数 :func:``update_last_applied_manifest_dict_from_resp`` 一起，该函数被递归调用，来从部分 Kubernetes 响应中更新部分 ``last_applied_manifest``。

    参数:
      last_applied_manifest (list): 正在更新的部分 ``last_applied_manifest``。
      observer_schema (list): 部分 ``observer_schema``。
      response (list): 来自 Kubernetes API 的部分响应。

    此函数会遍历所有观察到的字段，如果它们尚未在 `last_applied_manifest` 中初始化，则会为其初始化值。
    """
    for i, (schema_item, resp_item) in enumerate(zip(observer_schema, response)):
        if isinstance(schema_item, dict) and isinstance(resp_item, dict):
            if i >= len(last_applied_manifest):
                last_applied_manifest.append({})
            update_last_applied_manifest_dict_from_resp(last_applied_manifest[i], schema_item, resp_item)
        elif isinstance(schema_item, list) and isinstance(resp_item, list):
            if i >= len(last_applied_manifest):
                last_applied_manifest.append([])
            update_last_applied_manifest_list_from_resp(last_applied_manifest[i], schema_item, resp_item)
        else:
            if i >= len(last_applied_manifest):
                last_applied_manifest.append(resp_item)
            else:
                last_applied_manifest[i] = resp_item

def update_last_applied_manifest_dict_from_resp(last_applied_manifest, observer_schema, response):
    """
    与函数 :func:``update_last_applied_manifest_list_from_resp`` 一起，该函数被递归调用，用于从部分 Kubernetes 响应中更新部分 ``last_applied_manifest``。

    参数:
      last_applied_manifest (list): 正在更新的部分 ``last_applied_manifest``。
      observer_schema (list): 部分 ``observer_schema``。
      response (list): 来自 Kubernetes API 的部分响应。

    异常:
      KeyError: 如果在 Kubernetes 响应中未找到观察字段，则抛出此异常。

    此函数会遍历所有观察到的字段，如果它们尚未在 `last_applied_manifest` 中初始化，则会为其初始化值。
    """
    for field in observer_schema:
        if field not in response:
            raise KeyError(f"Field '{field}' not found in the Kubernetes response.")

        if field not in last_applied_manifest:
            last_applied_manifest[field] = response[field]
        elif isinstance(last_applied_manifest[field], dict) and isinstance(response[field], dict):
            update_last_applied_manifest_dict_from_resp(last_applied_manifest[field], observer_schema, response[field])
        elif isinstance(last_applied_manifest[field], list) and isinstance(response[field], list):
            update_last_applied_manifest_list_from_resp(last_applied_manifest[field], observer_schema, response[field])
        else:
            last_applied_manifest[field] = response[field]

def generate_default_observer_schema(app):
    """
    为 ``spec.manifest`` 中的每个 Kubernetes 资源生成默认的观察者模式（observer schema），前提是尚未为其指定自定义的观察者模式。

    参数：
      app (krake.data.kubernetes.Application): 需要为其生成默认观察者模式的应用程序。
    """
    for resource in app.spec.manifest:
        if not hasattr(resource, 'observer_schema'):
            # 生成默认的观察者模式
            resource.observer_schema = {
                "type": "object",
                "properties": {
                    "status": {
                        "type": "object",
                        "properties": {
                            "conditions": {
                                "type": "array",
                                "items": {
                                    "type": "object",
                                    "properties": {
                                        "type": {"type": "string"},
                                        "status": {"type": "string"},
                                        "lastTransitionTime": {"type": "string"},
                                        "reason": {"type": "string"},
                                        "message": {"type": "string"}
                                    },
                                    "required": ["type", "status"]
                                }
                            }
                        }
                    }
                },
                "required": ["status"]
            }
    return app

