def check_digests_present_and_used(self, manifest_files, digests_used):
    """
    检查清单（manifest）中所有需要的摘要（digest）是否存在并被使用。在类中返回 `error()`。
    """
    for manifest_file in manifest_files:
        if not manifest_file.get('digest'):
            return self.error(f"Digest missing in manifest file: {manifest_file}")

    for digest in digests_used:
        if not any(manifest_file.get('digest') == digest for manifest_file in manifest_files):
            return self.error(f"Digest not found in any manifest file: {digest}")

    return None

def validate_as_prior_version(self, prior):
    """
    检查 `prior` 是否是当前库存（inventory）对象的有效先前版本。

    输入变量 `prior` 也应是一个 `InventoryValidator` 对象，并且假定 `self` 和 `prior` 的库存对象都已经过内部一致性检查。在类中返回 `error()`。
    """
    if not isinstance(prior, InventoryValidator):
        return self.error("Prior version must be an instance of InventoryValidator.")

    # 假设我们有一些方法来比较两个库存对象的版本
    if not self.is_valid_prior_version(prior):
        return self.error("Prior version is not a valid previous version of the current inventory.")

    return None

def get_logical_path_map(inventory, version):
    """
    返回库存（inventory）中各状态的文件路径，并以字典类型表示。
    获取库存中某个版本的状态逻辑路径到磁盘文件的映射。

    返回一个字典：`logical_path_in_state -> set(content_files)`

    集合`content_files`可能包含对比所描述版本更高版本中重复文件的引用。
    """
    logical_path_map = {}

    for logical_path, file_versions in inventory.items():
        content_files = set()
        for file_version, file_path in file_versions.items():
            if file_version >= version:
                content_files.add(file_path)
        if content_files:
            logical_path_map[logical_path] = content_files

    return logical_path_map

def validate_fixity(self, fixity, manifest_files):
    """
    验证库存（inventory）中的校验（fixity）块。检查校验块的结构，并保证仅引用了清单中列出的文件。在类中返回`error()`。
    """
    if not isinstance(fixity, dict):
        return self.error("Fixity block must be a dictionary.")

    for file_path, checksums in fixity.items():
        if file_path not in manifest_files:
            return self.error(f"File {file_path} in fixity block is not listed in the manifest.")

        if not isinstance(checksums, dict):
            return self.error(f"Checksums for file {file_path} must be a dictionary.")

        for algorithm, checksum in checksums.items():
            if not isinstance(algorithm, str) or not isinstance(checksum, str):
                return self.error(f"Algorithm and checksum for file {file_path} must be strings.")

    return None

