def parser_flags(parser):
    """
    给定一个 `argparse.ArgumentParser` 实例，返回其参数标志（flags）组成的以空格分隔的字符串。
    """
    flags = []
    for action in parser._actions:
        if action.option_strings:
            flags.extend(action.option_strings)
    return ' '.join(flags)

def parse_subparser_arguments(unparsed_arguments, subparsers):
    """
    给定一个参数序列和一个从子解析器名称到 argparse.ArgumentParser 实例的字典，让每个请求的操作的子解析器尝试解析所有参数。这允许共享常见参数（例如 --repository）给多个子解析器。

    将结果作为一个元组返回，其中包含一个将子解析器名称映射到其解析后的 argparse.Namespace 实例的字典和一个包含未被任何子解析器认领的剩余参数的列表。
    """
    parsed_results = {}
    remaining_args = list(unparsed_arguments)

    for name, parser in subparsers.items():
        try:
            # Try to parse the arguments with the current subparser
            parsed_args, remaining = parser.parse_known_args(unparsed_arguments)
            if parsed_args:
                parsed_results[name] = parsed_args
                # Update the remaining_args to exclude the ones parsed by this subparser
                remaining_args = remaining
        except SystemExit:
            # If parsing fails, continue to the next subparser
            continue

    return parsed_results, remaining_args

def deep_merge_nodes(nodes):
    merged = {}

    for key_node, value_node in nodes:
        key = key_node.value

        if key in merged:
            existing_value_node = merged[key]

            if isinstance(existing_value_node, MappingNode) and isinstance(value_node, MappingNode):
                # Recursively merge the MappingNodes
                merged_value = deep_merge_nodes(existing_value_node.value + value_node.value)
                merged[key] = MappingNode(tag=existing_value_node.tag, value=merged_value)
            else:
                # If either value is not a MappingNode, keep the last value
                merged[key] = value_node
        else:
            merged[key] = value_node

    # Convert the merged dictionary back to a list of tuples
    return [(ScalarNode(tag='tag:yaml.org,2002:str', value=key), value_node) for key, value_node in merged.items()]

def parser_flags(parser):
    """
