    """
    flags = []
    for action in parser._actions:
        if action.option_strings:
            flags.extend(action.option_strings)
    return ' '.join(flags)

from typing import List, Optional

def int_to_string(number: int, alphabet: List[str], padding: Optional[int] = None) -> str:
    """
    将一个数字使用给定的字母表转换为字符串。

    数字表示一个短的 UUID。

    输出的字符串以最高有效位（Most Significant Digit）优先。

    @param number: 整型值  
    @param alphabet: 包含字母的列表  
    @param padding: 可选参数，整型值，用于指定填充长度  
    @return: 与整型值对应的字符串值
    """
    base = len(alphabet)
    result = []

    while number > 0:
        remainder = number % base
        result.append(alphabet[remainder])
        number = number // base

    # Reverse to get the most significant digit first
    result.reverse()

    # Convert list to string
    result_str = ''.join(result)

    # Apply padding if specified
    if padding is not None:
        if len(result_str) < padding:
            result_str = alphabet[0] * (padding - len(result_str)) + result_str

    return result_str

from datetime import timedelta

def parse_frequency(frequency):
    if frequency is None or frequency.lower() == "always":
        return None

    try:
        parts = frequency.strip().split()
        if len(parts) != 2:
            raise ValueError("Invalid frequency format. Expected format: 'number timeunit'")

        num = int(parts[0])
        unit = parts[1].lower()

        if unit in ['days', 'day']:
            return timedelta(days=num)
        elif unit in ['weeks', 'week']:
            return timedelta(weeks=num)
        elif unit in ['hours', 'hour']:
            return timedelta(hours=num)
        elif unit in ['minutes', 'minute']:
            return timedelta(minutes=num)
        elif unit in ['seconds', 'second']:
            return timedelta(seconds=num)
        else:
            raise ValueError(f"Unsupported time unit: {unit}")

    except ValueError as e:
        raise ValueError(f"Failed to parse frequency: {frequency}. Error: {e}")

import re

def get_pattern(pattern, strip=True):
    """
    将字符串转换为正则表达式模式对象

    参数:
      pattern: 字符串或正则表达式模式对象
      strip: 布尔值，是否去除字符串开头和结尾的空格
    返回值:
      正则表达式模式对象

    此方法将给定的字符串转换为正则表达式模式。
    """
    if isinstance(pattern, str):
        if strip:
            pattern = pattern.strip()
        return re.compile(pattern)
    elif isinstance(pattern, re.Pattern):
        return pattern
    else:
        raise TypeError("pattern must be a string or a compiled regex pattern")

def force_string(obj):
    """
    如果对象是 `numpy.bytes` 或 `bytes` 类型，则强制使用 'utf-8' 解码。

    参数：
      obj: 一致性配置
    返回值：
      如果对象是字符串类型，则返回对应的 UTF-8 编码的字节对象；否则，直接返回该对象。

    此函数在对象是字符串的情况下，返回对应的 UTF-8 编码的字节对象。
    """
    if isinstance(obj, (bytes, np.bytes_)):
        return obj.decode('utf-8')
    elif isinstance(obj, str):
        return obj.encode('utf-8')
    else:
        return obj

def protocol_handlers(cls, protocol_version=None):
    """
    返回一个可用的 Bolt 协议处理程序的字典，以版本元组为键。如果提供了明确的协议版本，字典将包含零个或一个条目，具体取决于该版本是否受支持。如果未提供协议版本，将返回所有可用的版本。

    :param protocol_version: 标识特定协议版本的元组（例如 (3, 5)）或 None
    :return: 一个字典，键为版本元组，值为所有相关且受支持的协议版本的处理程序类
    :raise TypeError: 如果协议版本未以元组形式传入
    """
    # 假设我们有一些支持的协议版本及其对应的处理程序
    supported_handlers = {
        (3, 5): "BoltV3_5Handler",
        (4, 0): "BoltV4_0Handler",
        (4, 1): "BoltV4_1Handler",
    }

    if protocol_version is not None:
        if not isinstance(protocol_version, tuple):
            raise TypeError("协议版本必须以元组形式传入")
        if protocol_version in supported_handlers:
            return {protocol_version: supported_handlers[protocol_version]}
        else:
            return {}
    else:
        return supported_handlers

def _get_seq_with_type(seq, bufsize=None):
    """
    返回一个 (sequence, type) 对。
    sequence 是从 *seq* 派生的
    （或者是 *seq* 本身，如果它是一个序列类型）。
    """
    if isinstance(seq, (list, tuple, str, bytes, bytearray)):
        return seq, type(seq)
    else:
        return list(seq), list

def scale(self, other=None, recompute=False):
    """
    计算或设置直方图的比例（积分值）。

    如果参数 *other* 为 ``None``，则返回当前直方图的比例。
    如果之前未计算过比例值，则会计算并存储该值以供后续使用（除非明确要求重新计算）。
    请注意，在对直方图进行更改（填充数据）后，如果之前已计算过比例值，则需要显式地重新计算比例。

    如果提供了一个浮点数 *other*，则将当前直方图的比例调整为 *other*。

    无法对比例为零的直方图进行重新调整。如果尝试这样做，将会引发 :exc:`.LenaValueError` 异常。
    """
    if other is None:
        if not hasattr(self, '_scale') or recompute:
            self._scale = self._compute_scale()
        return self._scale
    else:
        if not isinstance(other, (int, float)):
            raise TypeError("Scale must be a float or integer.")
        if self._scale == 0:
            raise LenaValueError("Cannot rescale a histogram with zero scale.")
        self._scale = float(other)

def _compute_scale(self):
    """
    计算直方图的比例（积分值）。
    """
    # 假设 self._data 是直方图的数据
    return sum(self._data)

def scale(self, other=None):
    """
    获取或设置图表的比例。

    如果参数 *other* 为 ``None``，则返回此图表的比例。

    如果提供了一个数值类型的 *other*，则将图表重新缩放到该值。
    如果图表的比例未知或为零，对其重新缩放将会引发:exc: `~.LenaValueError` 异常。

    为了获得有意义的结果，将使用图表的字段。
    仅最后一个坐标会被重新缩放。
    例如，如果图表具有 *x* 和 *y* 坐标，则 *y* 会被重新缩放；对于三维图表，*z* 会被重新缩放。
    所有的误差值也会与其对应的坐标一起重新缩放。
    """
    if other is None:
        return self._scale
    elif isinstance(other, (int, float)):
        if self._scale == 0 or self._scale is None:
            raise LenaValueError("Cannot rescale chart with unknown or zero scale.")
        # Rescale the last coordinate
        if hasattr(self, 'z'):
            self.z *= other / self._scale
            if hasattr(self, 'z_error'):
                self.z_error *= other / self._scale
        elif hasattr(self, 'y'):
            self.y *= other / self._scale
            if hasattr(self, 'y_error'):
                self.y_error *= other / self._scale
        elif hasattr(self, 'x'):
            self.x *= other / self._scale
            if hasattr(self, 'x_error'):
                self.x_error *= other / self._scale
        self._scale = other
    else:
        raise TypeError("Scale must be a numeric value or None.")

def determineMetaclass(bases, explicit_mc=None):
    """
    从一个或多个基类以及可选的显式 __metaclass__ 中确定元类。
    """
    if explicit_mc is not None:
        return explicit_mc
    for base in bases:
        if hasattr(base, '__class__'):
            return base.__class__
    return type

def pop(self, key, default=__marker):
    """
    `D.pop(k[, d]) -> v`：移除指定的键并返回对应的值。  
    如果未找到指定的键，则返回 `d`（如果提供了 `d`）；否则会引发 `KeyError` 异常。
    """
    if key in self:
        value = self[key]
        del self[key]
        return value
    elif default is not __marker:
        return default
    else:
        raise KeyError(key)

def popitem(self):
    """
    移除并返回最久未使用的键值对。
    """
    if not self:
        raise KeyError("popitem(): dictionary is empty")
    key = next(iter(self))
    value = self.pop(key)
    return (key, value)

def popitem(self):
    """
    移除并返回最近使用的键值对。
    """
    if not self:
        raise KeyError("popitem(): dictionary is empty")
    key = next(reversed(self))
    value = self.pop(key)
    return (key, value)

def _create_converter(self) -> _converting._Converter:
    """
    创建参数样式转换器。

    返回参数样式转换器 (:class:`._converting._Converter`)。
    """
    return _converting._Converter()

def fromutc(self, dt):
    """
    给定一个在给定时区中带有时区信息的日期时间对象，计算在新时区的带有时区信息的日期时间。

    由于这是我们*明确知道*日期时间对象没有歧义的唯一时刻，我们利用这个机会来判断该日期时间是否存在歧义，并且是否处于“折叠”状态（例如，如果这是歧义日期时间的第一个按时间顺序出现的实例）。

    :param dt: 一个带有时区信息的 :class:`datetime.datetime` 对象。
    """
    if dt.tzinfo is None:
        raise ValueError("fromutc() requires a timezone-aware datetime")

    # Convert the datetime to the local timezone
    local_dt = dt.astimezone(self)

    # Check if the local datetime is ambiguous
    if self.is_ambiguous(local_dt):
        # If ambiguous, return the first occurrence
        return local_dt.replace(fold=0)
    else:
        return local_dt

from datetime import datetime, timezone

def ensure_timezone(dt):
    """
    确保给定的 datetime 对象具有时区信息。
    如果 dt 没有时区信息，则默认设置为 UTC。
    """
    if dt.tzinfo is None:
        return dt.replace(tzinfo=timezone.utc)
    return dt

def format_dt(dt):
    """
    使用 `ensure_timezone` 函数格式化 `dt` 的时间并返回时间。

    以 D* 节点期望的方式格式化日期时间。
    """
    dt_with_tz = ensure_timezone(dt)
    return dt_with_tz.isoformat()

def test_tag(tag: str) -> bool:
    """
    检查 `LEGAL_TAG_CHARS` 中的每个字符是否属于标签。如果有任何字符属于标签，则返回假。否则，返回真。

    测试一个单词是否可以被接受为标签。
    """
    LEGAL_TAG_CHARS = set("abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789-_")

    for char in tag:
        if char not in LEGAL_TAG_CHARS:
            return False
    return True

def xml_children_as_dict(node):
    """
    将 <xml> 节点的子节点转换为一个字典，以标签名称作为键。

    这只是一个浅层转换——子节点不会被递归处理。
    """
    result = {}
    for child in node:
        if child.tag not in result:
            result[child.tag] = []
        result[child.tag].append(child.text)
    return result

import json
from typing import Dict

def parse_diaspora_webfinger(document: str) -> Dict:
    """
    通过读取 JSON 格式的文档获取 Webfinger，Webfinger 中的 `hcard_url` 值是文档中 `links` 的 `href` 值。

    解析 Diaspora 的 Webfinger，该 Webfinger 可以是 JSON 格式（新格式）或 XRD 格式（旧格式）。

    https://diaspora.github.io/diaspora_federation/discovery/webfinger.html
    """
    try:
        data = json.loads(document)
        if isinstance(data, dict):
            if 'links' in data:
                for link in data['links']:
                    if isinstance(link, dict) and 'rel' in link and link['rel'] == 'http://microformats.org/profile/hcard':
                        return {'hcard_url': link.get('href')}
            elif 'subject' in data:
                # Handle XRD format
                for link in data.get('links', []):
                    if isinstance(link, dict) and 'rel' in link and link['rel'] == 'http://microformats.org/profile/hcard':
                        return {'hcard_url': link.get('href')}
        return {}
    except json.JSONDecodeError:
        # Handle non-JSON format (e.g., XRD format)
        # This is a simplified approach, as XRD parsing would require more complex handling
        return {}

import requests
from lxml import etree

def retrieve_and_parse_diaspora_webfinger(handle):
    """
    检索并解析远程 Diaspora WebFinger 文档。

    :arg handle: 要检索的远程句柄
    :returns: 字典
    """
    # 构造 WebFinger URL
    webfinger_url = f"https://{handle.split('@')[1]}/.well-known/webfinger?resource=acct:{handle}"

    try:
        # 发送 GET 请求获取 WebFinger 文档
        response = requests.get(webfinger_url)
        response.raise_for_status()

        # 解析 XML 文档
        root = etree.fromstring(response.content)

        # 提取所需信息
        result = {
            "subject": root.find(".//{http://webfinger.net/rel/profile-page}subject").text,
            "aliases": [alias.text for alias in root.findall(".//{http://webfinger.net/rel/profile-page}alias")],
            "links": []
        }

        for link in root.findall(".//{http://webfinger.net/rel/profile-page}link"):
            link_info = {
                "rel": link.get("rel"),
                "type": link.get("type"),
                "href": link.get("href")
            }
            result["links"].append(link_info)

        return result

    except requests.exceptions.RequestException as e:
        print(f"请求失败: {e}")
        return {}
    except etree.XMLSyntaxError as e:
        print(f"XML 解析失败: {e}")
        return {}

import requests

def send_document(url, data, timeout=10, method="post", *args, **kwargs):
    """
    通过POST方法发送包含数据的响应。

    用于通过POST方法发送文档的辅助方法。

    额外的``*args``和``**kwargs``参数将会传递给``requests.post``。

    :arg url: 完整的目标URL，包括协议
    :arg data: 要在请求体中发送的数据，可以是字典（将会被表单编码）、字节数据或类似文件的对象。
    :arg timeout: 等待响应的超时时间（以秒为单位，默认为10秒）。
    :arg method: 使用的HTTP方法，默认为POST。
    :return: 返回一个元组，包含状态码（整数或None）和错误信息（异常类实例或None）。
    """
    try:
        if method.lower() == "post":
            response = requests.post(url, data=data, timeout=timeout, *args, **kwargs)
        elif method.lower() == "get":
            response = requests.get(url, params=data, timeout=timeout, *args, **kwargs)
        else:
            raise ValueError(f"Unsupported HTTP method: {method}")

        response.raise_for_status()
        return (response.status_code, None)

    except requests.exceptions.RequestException as e:
        return (None, e)

