def validate_from_content(cls, spec_content=None):
    """
    验证规范（YAML）内容是否包含所有必需字段。

    :param spec_content: 规范文件的内容
    :raise IRValidatorException: 当规范文件中缺少必需数据时抛出异常
    :return: 从规范（YAML）文件加载的数据字典
    """
    import yaml
    from yaml import YAMLError

    if spec_content is None:
        raise ValueError("spec_content cannot be None")

    try:
        data = yaml.safe_load(spec_content)
    except YAMLError as e:
        raise IRValidatorException(f"Invalid YAML content: {e}")

    required_fields = ['field1', 'field2', 'field3']  # Replace with actual required fields

    for field in required_fields:
        if field not in data:
            raise IRValidatorException(f"Missing required field: {field}")

    return data

import yaml

class IRValidatorException(Exception):
    pass

def validate_from_file(cls, yaml_file=None):
    """
    加载并验证一个 YAML 文件是否包含所有必需字段

    :param yaml_file: YAML 文件的路径
    :raise IRValidatorException: 当文件中缺少必需数据时抛出异常
    :return: 从 YAML 文件加载的数据字典
    """
    if yaml_file is None:
        raise IRValidatorException("YAML file path is required.")

    try:
        with open(yaml_file, 'r') as file:
            data = yaml.safe_load(file)
    except Exception as e:
        raise IRValidatorException(f"Failed to load YAML file: {e}")

    # Assuming required_fields is a list of required fields
    required_fields = ['field1', 'field2', 'field3']  # Example required fields

    for field in required_fields:
        if field not in data:
            raise IRValidatorException(f"Missing required field: {field}")

    return data

def _include_groups(self, parser_dict):
    """
    解析规范文件中的 include dict 指令。
    """
    if 'include' in parser_dict:
        for group in parser_dict['include']:
            if group in parser_dict:
                parser_dict.update(parser_dict[group])
            else:
                raise ValueError(f"Group '{group}' not found in parser_dict")
    return parser_dict

def get_spec_defaults(self):
    """
    使用 `self._get_defaults()` 从规范和其他来源解析参数的值。

    从规范和其他来源解析参数的值。
    """
    return self._get_defaults()

def get_deprecated_args(self):
    """
    返回一个包含会弃用其他选项的字典。选项来自 `self.spec_helper.iterate_option_specs()`。
    返回一个包含会弃用其他选项的字典。
    """
    deprecated_args = {}
    for option_spec in self.spec_helper.iterate_option_specs():
        if 'deprecated_by' in option_spec:
            deprecated_args[option_spec['name']] = option_spec['deprecated_by']
    return deprecated_args

def validate_length_args(self, args):
    """
    检查给定参数的值是否不超过指定的长度。

    :param args: 接收到的参数。
    """
    max_length = 100  # 假设最大长度为100
    for arg in args:
        if len(str(arg)) > max_length:
            raise ValueError(f"参数 {arg} 的长度超过了最大允许长度 {max_length}")

def validate_choices_args(self, args):
    """
    检查给定参数的值是否是可用选项之一。

    :param args: 接收到的参数。
    """
    if not hasattr(self, 'choices'):
        raise AttributeError("The 'choices' attribute is not defined.")

    if not isinstance(self.choices, (list, tuple, set)):
        raise TypeError("The 'choices' attribute must be a list, tuple, or set.")

    if args not in self.choices:
        raise ValueError(f"The argument '{args}' is not a valid choice. Valid choices are: {self.choices}")

    return True

def validate_min_max_args(self, args):
    """
    检查给定参数的值是否在最小值和最大值之间

    检查参数的值是否在最小值和最大值之间
    :param args: 接收到的参数。
    """
    if not hasattr(self, 'min_value') or not hasattr(self, 'max_value'):
        raise ValueError("min_value and max_value must be defined in the class.")

    for arg in args:
        if not (self.min_value <= arg <= self.max_value):
            return False
    return True

def get_nested_custom_and_control_args(self, args):
    """
    将输入参数分为控制，嵌套和自定义参数。

    控制参数：用于控制中间表示的行为。这些参数不会被写入到规范yml文件中。  
    嵌套参数：用于Ansible playbooks，并会被写入到规范yml文件中。  
    自定义参数：自定义的Ansible变量，用于替代常规的嵌套参数使用。

    :param args: 收集到的参数列表。
    :return: (dict, dict): 扁平化的字典（control_args, nested_args）
    """
    control_args = {}
    nested_args = {}

    for key, value in args.items():
        if key.startswith('control_'):
            control_args[key] = value
        elif key.startswith('nested_'):
            nested_args[key] = value
        else:
            nested_args[key] = value

    return control_args, nested_args

def merge_extra_vars(vars_dict, extra_vars=None):
    """
    使用 ``extra-vars`` 扩展 ``vars_dict``。

    :param vars_dict: 要合并 extra-vars 的字典
    :param extra_vars: extra-vars的列表
    """
    if extra_vars is None:
        return vars_dict

    for var in extra_vars:
        if '=' in var:
            key, value = var.split('=', 1)
            vars_dict[key] = value
        else:
            vars_dict[var] = True

    return vars_dict

import subprocess

def ansible_playbook(ir_workspace, ir_plugin, playbook_path, verbose=None, extra_vars=None, ansible_args=None):
    """
    封装 'ansible-playbook' 命令行接口。
    :param ir_workspace: 一个 Infrared Workspace 对象，表示当前活动的工作区
    :param ir_plugin: 当前插件的一个 InfraredPlugin 对象
    :param playbook_path: 要调用的 playbook 文件路径
    :param verbose: Ansible 的详细级别
    :param extra_vars: dict。作为额外变量 (extra-vars) 传递给 Ansible
    :param ansible_args: ansible-playbook 参数的字典，直接传递给 Ansible
    """
    command = ["ansible-playbook", playbook_path]

    if verbose:
        command.append(f"-{verbose}")

    if extra_vars:
        extra_vars_str = " ".join([f"{k}={v}" for k, v in extra_vars.items()])
        command.extend(["--extra-vars", extra_vars_str])

    if ansible_args:
        for arg, value in ansible_args.items():
            if value is True:
                command.append(f"--{arg}")
            else:
                command.extend([f"--{arg}", str(value)])

    try:
        result = subprocess.run(command, check=True, capture_output=True, text=True)
        return result.stdout
    except subprocess.CalledProcessError as e:
        print(f"Ansible playbook execution failed: {e.stderr}")
        raise

def _convert_non_cli_args(self, parser_name, values_dict):
    """
    通过修改 values_dict 参数将参数转换为正确的类型。

    默认情况下，所有的值都是字符串。

    :param parser_name: 命令名称，例如 main、virsh、ospd 等
    :param values_dict: 包含参数的字典
    """
    for key, value in values_dict.items():
        if isinstance(value, str):
            # 尝试将字符串转换为整数
            if value.isdigit():
                values_dict[key] = int(value)
            # 尝试将字符串转换为浮点数
            elif value.replace('.', '', 1).isdigit():
                values_dict[key] = float(value)
            # 尝试将字符串转换为布尔值
            elif value.lower() in ('true', 'false'):
                values_dict[key] = value.lower() == 'true'
            # 其他情况保持为字符串
            else:
                values_dict[key] = value
    return values_dict

import os
import yaml

def get_plugin_spec_flatten_dict(plugin_dir):
    """
    使用 YAML 来读取 `plugin_dir` 中的各种信息，并以字典形式将其返回。
    从插件规范创建一个扁平化的字典

    :param plugin_dir: 插件目录的路径
    :return: 一个包含插件属性的扁平化字典
    """
    spec_file = os.path.join(plugin_dir, 'plugin_spec.yaml')
    if not os.path.exists(spec_file):
        raise FileNotFoundError(f"Plugin spec file not found in {plugin_dir}")

    with open(spec_file, 'r') as file:
        spec_data = yaml.safe_load(file)

    # Flatten the dictionary
    flattened_dict = {}
    for key, value in spec_data.items():
        if isinstance(value, dict):
            for sub_key, sub_value in value.items():
                flattened_dict[f"{key}.{sub_key}"] = sub_value
        else:
            flattened_dict[key] = value

    return flattened_dict
